// // This module implements a 5-bit binary counter that counts down by 1 on each clock cycle when the enable signal is high. When the clear signal is high, the counter should be cleared to 0.
module binary_counter_with_clear (
	input clk,
	input clear,
	input enable,
	output reg [4:0] count);

	always @(posedge clk) begin
		if (clear)
			count <= 5'b00000;
		else if (enable)
			count <= count + 1;
	end

endmodule
